def set_cached_response(key, value, expiry=0):
    data = {
        "timestamp": time.time(),
        "expiry": expiry,
        "value": value
    }

    with open(f"{cache_dir}/{key}", 'w') as file:
        json.dump(data, file)
    
@app.route('/api/<string:endpoint>', methods=['GET'])
def api_with_caching(endpoint):
    expiry = request.args.get('expiry', default = 0, type = int)  # Expiry time in seconds
  
    cached_response = get_cached_response(endpoint, expiry)
    
    if not cached_response:
        # TODO: Replace with actual API request code
        response = {'data': 'sample data'}
        
        set_cached_response(endpoint, response, expiry)
      
